-- 0001_seed_models.sql
-- Seed catalogue for the `models` table (DDL lives in db/schema.sql).
-- Run after schema.sql on a fresh install. Idempotent via ON CONFLICT DO NOTHING.
--
-- Editorial columns:
--   gated            TRUE = HuggingFace approval required (Meta Llama, Gemma 3, etc.)
--   native_quant     What the weight files actually are (bf16 for base repos,
--                    nvfp4 for NVIDIA ModelOpt pre-quantised repos).
--   supported_quants Native quant plus anything we can serve on-the-fly (e.g.
--                    bf16 + fp8 via vLLM at load time).

ON CONFLICT (hf_repo_id) DO NOTHING;
